"use client";
import React, { useState, useEffect } from 'react';
import { 
  Card, 
  Container, 
  Button, 
  Row, 
  Col, 
  Form, 
  Alert, 
  Spinner,
  Table,
  Modal
} from 'react-bootstrap';
import { useRouter } from 'next/navigation';
import { 
  FaFileAlt, 
  FaCheck, 
  FaCreditCard, 
  FaMoneyBillWave, 
  FaUniversity,
  FaDownload,
  FaCheckCircle,
  FaArrowRight
} from 'react-icons/fa';
import toast from 'react-hot-toast';
import Script from 'next/script';
import axios from 'axios';

interface OfferLetterData {
  fullName: string;
  programName: string;
  universityName: string;
  startDate: string;
  [key: string]: any;
}

// Declare Razorpay as a global variable 
declare global {
  interface Window {
    Razorpay: any;
  }
}

export default function PaymentPage() {
  const [loading, setLoading] = useState(false);
  const [processingPayment, setProcessingPayment] = useState(false);
  const [user, setUser] = useState<any>({});
  const [hasOfferLetter, setHasOfferLetter] = useState(false);
  const [paymentCompleted, setPaymentCompleted] = useState(false);
  const [offerLetterData, setOfferLetterData] = useState<OfferLetterData>({
    fullName: '',
    programName: '',
    universityName: '',
    startDate: ''
  });
  const [showSuccessModal, setShowSuccessModal] = useState(false);
  const [paymentMethod, setPaymentMethod] = useState('credit');
  const [cardData, setCardData] = useState({
    cardNumber: '',
    cardName: '',
    expiryDate: '',
    cvv: ''
  });
  const [razorpayLoaded, setRazorpayLoaded] = useState(false);
  
  const router = useRouter();
  
  // Application fee (would come from API in real app)
  const applicationFee = 350;

  const Amount = 350 * 100; // Converting to paise as Razorpay expects amount in smallest currency unit
  const formattedAmount = (Amount / 100).toLocaleString("en-IN", {
    style: "currency",
    currency: "INR",
    maximumFractionDigits: 0,
  });

  const [isProcessing, setIsProcessing] = useState(false);

  // Handle Razorpay script load
  const handleRazorpayLoad = () => {
    setRazorpayLoaded(true);
    console.log("Razorpay SDK loaded successfully");
  };

  useEffect(() => {
    const userData = localStorage.getItem("user");
    if (userData) {
      setUser(JSON.parse(userData));
    } else {
      router.push("/login");
    }
  }, [router]);

  // Handle payment success
  const handlePaymentSuccess = async (response: any) => {
    try {
      setProcessingPayment(true);
      
      // Log the payment response
      console.log("Payment success response:", response);
      
      // Frontend-only implementation - no backend calls
      toast.success("Payment successful!");
      localStorage.setItem('payment_completed', 'true');
      setPaymentCompleted(true);
      setShowSuccessModal(true);
      setProcessingPayment(false);
    } catch (error) {
      console.error("Payment error:", error);
      toast.error("Error processing payment. Please try again.");
      setProcessingPayment(false);
    }
  };

  const handlePayment = async () => {
    setIsProcessing(true);

    try {
      if (!user) {
        toast.error("User information not found");
        setIsProcessing(false);
        return;
      }

      if (!window.Razorpay) {
        toast.error("Payment gateway not loaded. Please refresh the page.");
        setIsProcessing(false);
        return;
      }

      // Generate a dummy order ID for demo purposes
      const order_id = "order_" + Math.random().toString(36).substring(2, 15);

      const options = {
        key: "rzp_test_iyUXOGQ3QN55KA", // Test key
        amount: Amount,
        currency: "INR",
        name: "Bring Your Buddy",
        description: "University Application Fee",
        order_id: order_id,
        prefill: {
          name: user.name || "",
          email: user.email || "",
          contact: user.phone_number || "",
        },
        theme: {
          color: "#1A73E8",
        },
        modal: {
          ondismiss: function() {
            console.log('Payment modal closed');
            setIsProcessing(false);
          },
          confirm_close: true,
        },
        handler: function(response: any) {
          handlePaymentSuccess(response);
        },
      };

      console.log("Opening Razorpay with options:", options);
      
      const rzp = new window.Razorpay(options);
      
      rzp.on("payment.failed", function(response: any) {
        console.error("Payment failed:", response.error);
        toast.error("Payment failed. Please try again.");
        setIsProcessing(false);
      });

      rzp.open();
    } catch (err) {
      console.error("Error initiating payment:", err);
      toast.error("Something went wrong. Please try again.");
      setIsProcessing(false);
    }
  };
  
  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      
      // Check if offer letter exists
      const offerGenerated = localStorage.getItem('offerletter') === 'true';
      setHasOfferLetter(offerGenerated);
      
      // Check if payment already completed
      const paymentDone = localStorage.getItem('payment_completed') === 'true';
      setPaymentCompleted(paymentDone);
      
      // Get offer letter data
      const offerDataString = localStorage.getItem('offer_letter_data');
      if (offerDataString) {
        try {
          const offerData = JSON.parse(offerDataString);
          setOfferLetterData(offerData);
        } catch (error) {
          console.error('Error parsing offer letter data:', error);
        }
      }
      
      // Get user data
      const userData = localStorage.getItem("user");
      if (userData) {
        setUser(JSON.parse(userData));
      }
      
      setLoading(false);
    };
    
    fetchData();
  }, []);

  const handleCardInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setCardData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handlePaymentMethodChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setPaymentMethod(e.target.value);
  };

  // Use Razorpay if method is credit, otherwise use the process payment function
  const handleProcessPayment = () => {
    if (paymentMethod === 'credit') {
      handlePayment();
    } else {
      setProcessingPayment(true);
      
      // Simulate bank transfer processing
      setTimeout(() => {
        localStorage.setItem('payment_completed', 'true');
        setPaymentCompleted(true);
        setProcessingPayment(false);
        setShowSuccessModal(true);
      }, 2500);
    }
  };

  const closeSuccessModal = () => {
    setShowSuccessModal(false);
    router.push('/dashboard');
  };

  const handleDownloadOfferLetter = () => {
    // In a real application, this would download the actual offer letter PDF
    toast('Offer letter download started');
  };

  if (!hasOfferLetter) {
    return (
      <Container className="py-5">
        <Alert variant="warning">
          <Alert.Heading>Offer Letter Required</Alert.Heading>
          <p>
            You need to generate an offer letter before proceeding to payment.
            Please go to the Offer Letter page first.
          </p>
          <div className="d-flex justify-content-end">
            <Button 
              variant="outline-primary" 
              onClick={() => router.push('/applications/offerletter')}
            >
              Generate Offer Letter
            </Button>
          </div>
        </Alert>
      </Container>
    );
  }

  if (loading) {
    return (
      <Container className="py-5 text-center">
        <Spinner animation="border" variant="primary" />
        <p className="mt-3">Loading payment information...</p>
      </Container>
    );
  }

  return (
    <>
      {/* Load Razorpay Script */}
      <Script
        src="https://checkout.razorpay.com/v1/checkout.js"
        onLoad={handleRazorpayLoad}
        strategy="lazyOnload"
      />
      
      <Container className="py-4">
        <div className="page-header mb-4">
          <h4>
            <FaMoneyBillWave className="me-2" />
            Application Payment
          </h4>
          <p className="text-muted">
            Complete your application process by paying the application fee
          </p>
        </div>

        <Row>
          <Col lg={8}>
            <Card className="shadow-sm mb-4">
              <Card.Header className="bg-light">
                <h5 className="mb-0">Payment Details</h5>
              </Card.Header>
              <Card.Body>
                {paymentCompleted ? (
                  <div className="text-center py-4">
                    <div className="mb-4">
                      <div className="success-icon-container mx-auto mb-3">
                        <FaCheck className="text-success" size={40} />
                      </div>
                      <h4>Payment Completed!</h4>
                      <p className="text-muted">
                        Your payment has been successfully processed. Your application is now complete.
                      </p>
                    </div>
                    
                    <div className="d-flex justify-content-center gap-3">
                      <Button 
                        variant="outline-primary"
                        onClick={handleDownloadOfferLetter}
                        className="d-flex align-items-center"
                      >
                        <FaDownload className="me-2" /> Download Receipt
                      </Button>
                      <Button 
                        variant="primary"
                        onClick={() => router.push('/dashboard')}
                        className="d-flex align-items-center"
                      >
                        Go to Dashboard <FaArrowRight className="ms-2" />
                      </Button>
                    </div>
                  </div>
                ) : (
                  <>
                    <div className="offer-summary mb-4">
                      <h5 className="mb-3">Offer Letter Summary</h5>
                      <Table bordered hover responsive className="offer-table">
                        <tbody>
                          <tr>
                            <th>Name</th>
                            <td>{offerLetterData.fullName || user.name || "Not specified"}</td>
                          </tr>
                          <tr>
                            <th>Program</th>
                            <td>{offerLetterData.programName || "Not specified"}</td>
                          </tr>
                          <tr>
                            <th>University</th>
                            <td>{offerLetterData.universityName || "Not specified"}</td>
                          </tr>
                          <tr>
                            <th>Start Date</th>
                            <td>{offerLetterData.startDate || "Not specified"}</td>
                          </tr>
                          <tr>
                            <th>Application Fee</th>
                            <td className="fw-bold">${applicationFee}</td>
                          </tr>
                        </tbody>
                      </Table>
                      <div className="mt-3">
                        <Button 
                          variant="outline-secondary" 
                          size="sm"
                          onClick={handleDownloadOfferLetter}
                          className="d-flex align-items-center"
                        >
                          <FaFileAlt className="me-2" /> View Offer Letter
                        </Button>
                      </div>
                    </div>
                    
                    <hr className="my-4" />
                    
                    <div className="payment-methods mb-4">
                      <h5 className="mb-3">Select Payment Method</h5>
                      <Form>
                        <div className="d-flex gap-3 mb-4">
                          <Form.Check
                            type="radio"
                            id="credit-card"
                            name="paymentMethod"
                            label={
                              <div className="d-flex align-items-center">
                                <FaCreditCard className="me-2" /> Razorpay (Credit/Debit Card/UPI)
                              </div>
                            }
                            value="credit"
                            checked={paymentMethod === 'credit'}
                            onChange={handlePaymentMethodChange}
                            className="payment-method-radio"
                          />
                          <Form.Check
                            type="radio"
                            id="bank-transfer"
                            name="paymentMethod"
                            label={
                              <div className="d-flex align-items-center">
                                <FaUniversity className="me-2" /> Bank Transfer
                              </div>
                            }
                            value="bank"
                            checked={paymentMethod === 'bank'}
                            onChange={handlePaymentMethodChange}
                            className="payment-method-radio"
                          />
                        </div>
                        
                        {paymentMethod === 'credit' && (
                          <div className="credit-card-form">
                            <Alert variant="info">
                              <p>You will be redirected to Razorpay's secure payment page to complete your payment.</p>
                              <ul className="payment-features">
                                <li>Secure payment processing</li>
                                <li>Multiple payment options: Credit/Debit Cards, UPI, Wallets, Net Banking</li>
                                <li>Instant confirmation</li>
                              </ul>
                            </Alert>
                          </div>
                        )}
                        
                        {paymentMethod === 'bank' && (
                          <div className="bank-transfer-info">
                            <Alert variant="info">
                              <p className="mb-2">Please transfer the application fee to the following bank account:</p>
                              <Table bordered className="mt-2 bank-details-table">
                                <tbody>
                                  <tr>
                                    <th>Bank Name</th>
                                    <td>Global Education Bank</td>
                                  </tr>
                                  <tr>
                                    <th>Account Name</th>
                                    <td>University Applications</td>
                                  </tr>
                                  <tr>
                                    <th>Account Number</th>
                                    <td>1234567890</td>
                                  </tr>
                                  <tr>
                                    <th>Sort Code</th>
                                    <td>12-34-56</td>
                                  </tr>
                                  <tr>
                                    <th>Reference</th>
                                    <td>APP-{Math.floor(Math.random() * 100000)}</td>
                                  </tr>
                                </tbody>
                              </Table>
                              <p className="mt-3 small">
                                After making the transfer, click the "Confirm Payment" button below to complete your application.
                              </p>
                            </Alert>
                          </div>
                        )}
                        
                        <div className="d-grid gap-2 mt-4">
                          <Button 
                            variant="primary" 
                            size="lg"
                            onClick={handleProcessPayment}
                            disabled={processingPayment || isProcessing || (paymentMethod === 'credit' && !razorpayLoaded)}
                          >
                            {processingPayment || isProcessing ? (
                              <>
                                <Spinner
                                  as="span"
                                  animation="border"
                                  size="sm"
                                  role="status"
                                  aria-hidden="true"
                                  className="me-2"
                                />
                                Processing Payment...
                              </>
                            ) : (
                              <>Pay ${applicationFee}</>
                            )}
                          </Button>
                          {paymentMethod === 'credit' && !razorpayLoaded && (
                            <Alert variant="warning" className="mt-3">
                              <small>Payment gateway is still loading. Please wait or refresh the page if it takes too long.</small>
                            </Alert>
                          )}
                        </div>
                      </Form>
                    </div>
                  </>
                )}
              </Card.Body>
            </Card>
          </Col>
          
          <Col lg={4}>
            <Card className="shadow-sm mb-4">
              <Card.Header className="bg-light">
                <h5 className="mb-0">Payment Information</h5>
              </Card.Header>
              <Card.Body>
                <p>The application fee covers the processing of your application and is non-refundable.</p>
                <ul className="info-list">
                  <li>Application processing fee</li>
                  <li>Document verification</li>
                  <li>Administrative charges</li>
                  <li>Communication expenses</li>
                </ul>
                <div className="mt-4 payment-security-note">
                  <p className="text-muted">
                    <small>
                      <FaLock className="me-2" />
                      All payment information is securely processed. We do not store your credit card details.
                    </small>
                  </p>
                </div>
              </Card.Body>
            </Card>
          </Col>
        </Row>
        
        {/* Success Modal */}
        <Modal 
          show={showSuccessModal} 
          onHide={closeSuccessModal}
          centered
          backdrop="static"
        >
          <Modal.Header closeButton>
            <Modal.Title>Application Complete!</Modal.Title>
          </Modal.Header>
          <Modal.Body className="text-center py-4">
            <div className="success-icon-container mx-auto mb-3">
              <FaCheckCircle className="text-success" size={50} />
            </div>
            <h4>Thank You!</h4>
            <p>
              Your application has been successfully submitted and payment has been processed.
              You will receive a confirmation email shortly with further instructions.
            </p>
          </Modal.Body>
          <Modal.Footer>
            <Button variant="primary" onClick={closeSuccessModal}>
              Go to Dashboard
            </Button>
          </Modal.Footer>
        </Modal>

        <style jsx global>{`
          .success-icon-container {
            width: 100px;
            height: 100px;
            border-radius: 50%;
            background-color: rgba(40, 167, 69, 0.1);
            display: flex;
            align-items: center;
            justify-content: center;
          }
          
          .page-header {
            border-bottom: 1px solid #eee;
            padding-bottom: 1rem;
          }
          
          .info-list {
            padding-left: 20px;
          }
          
          .info-list li {
            margin-bottom: 0.5rem;
          }
          
          .payment-features {
            padding-left: 20px;
            margin-top: 10px;
          }
          
          .offer-table th {
            width: 30%;
            background-color: #f8f9fa;
          }
          
          .bank-details-table th {
            width: 40%;
            background-color: #f8f9fa;
          }
          
          .payment-method-radio {
            border: 1px solid #dee2e6;
            padding: 10px 15px;
            border-radius: 5px;
            cursor: pointer;
            transition: all 0.2s;
          }
          
          .payment-method-radio:hover {
            background-color: #f8f9fa;
          }
        `}</style>
      </Container>
    </>
  );
}

// FaLock component since it wasn't imported
const FaLock = (props: any) => (
  <svg 
    stroke="currentColor" 
    fill="currentColor" 
    strokeWidth="0" 
    viewBox="0 0 448 512" 
    height="1em" 
    width="1em" 
    xmlns="http://www.w3.org/2000/svg"
    {...props}
  >
    <path d="M400 224h-24v-72C376 68.2 307.8 0 224 0S72 68.2 72 152v72H48c-26.5 0-48 21.5-48 48v192c0 26.5 21.5 48 48 48h352c26.5 0 48-21.5 48-48V272c0-26.5-21.5-48-48-48zm-104 0H152v-72c0-39.7 32.3-72 72-72s72 32.3 72 72v72z"></path>
  </svg>
); 